import * as XLSX from 'xlsx';
import dayjs from 'dayjs';
import customParseFormat from 'dayjs/plugin/customParseFormat.js';

dayjs.extend(customParseFormat);

export const processCombinedData = (csvData, excelRaw) => {
  // --- 1. PROCESAR EXCEL (EASY DOCKING) ---
  const workbook = XLSX.read(excelRaw, { type: 'array' });
  const sheet = workbook.Sheets[workbook.SheetNames[0]];
  const rawMatrix = XLSX.utils.sheet_to_json(sheet, { header: 1 });

  // En tu imagen, los headers están en la fila 4 (índice 3)
  const headers = rawMatrix[3] ? rawMatrix[3].map(h => String(h).trim()) : [];
  const dataRows = rawMatrix.slice(4);

  const easyDockingClean = dataRows.map(row => {
    let obj = {};
    headers.forEach((h, i) => obj[h] = row[i]);
    return obj;
  }).filter(item => 
    // Filtros exactos según tu imagen: DESCARGA y add
    String(item['TIPO DE OPERACION']).toUpperCase() === "DESCARGA" && 
    String(item['Accion']).toLowerCase() === "add"
  );

  // SUMA DE PIEZAS (ARRIBOS) - Aquí llegamos a los 110.997
  const totalArribados = easyDockingClean.reduce((acc, curr) => {
    const valor = curr['CANT PAQUETES'] || 0; // NOTA: 'CANT PAQUETES' con S al final
    return acc + (parseFloat(valor) || 0);
  }, 0);

  // --- 2. PROCESAR CSV (TMS) ---
  // Cada fila es 1 pieza bipeada
  const totalBipeados = csvData.filter(d => 
    d['Labeling Date Printed'] && String(d['Labeling Date Printed']).trim() !== ""
  ).length;

  // --- 3. CÁLCULOS PARA KPIs ---
  const pendientes = totalArribados - totalBipeados;
  const eficiencia = totalArribados > 0 ? ((totalBipeados / totalArribados) * 100).toFixed(2) : "0.00";

  // --- 4. GRÁFICA (05:00 a 23:00) ---
  const franjas = [];
  for (let i = 5; i <= 23; i++) {
    franjas.push(`${i.toString().padStart(2, '0')}:00`);
  }

  const chartMap = {};
  franjas.forEach(h => chartMap[h] = { hora: h, arribo: 0, bipeo: 0 });

  // Llenar Arribos (Suma de CANT PAQUETES del Excel)
  easyDockingClean.forEach(row => {
    const fechaExcel = row['Fecha y Hora']; // Ajustado según imagen
    if (fechaExcel) {
      const hora = dayjs(fechaExcel).format('HH:00');
      if (chartMap[hora]) {
        chartMap[hora].arribo += (parseFloat(row['CANT PAQUETES']) || 0);
      }
    }
  });

  // Llenar Bipeos (Conteo de filas del CSV)
  csvData.forEach(row => {
    const fechaCsv = row['Labeling Date Printed'];
    if (fechaCsv) {
      const hora = dayjs(fechaCsv, "DD/MM/YYYY HH:mm:ss").format('HH:00');
      if (chartMap[hora]) chartMap[hora].bipeo++;
    }
  });

  return {
    kpis: {
      total: totalBipeados.toLocaleString(), // Piezas bipeadas reales
      pendientes: pendientes > 0 ? pendientes.toLocaleString() : "0", // 110.997 - bipeadas
      eficiencia: eficiencia
    },
    chartData: Object.values(chartMap),
    tableData: franjas.map(h => ({
      intervalo: h,
      etiquetado: 1000,
      piezas: chartMap[h].bipeo,
      usuarios: 12
    })),
    matrix: {
      chasis: easyDockingClean.filter(d => String(d['TRANSPORTE']).includes('Chasis')).length,
      camioneta: easyDockingClean.filter(d => String(d['TRANSPORTE']).toLowerCase().includes('Camioneta')).length,
      semi: easyDockingClean.filter(d => String(d['TRANSPORTE']).includes('Semi')).length
    }
  };
};
